 Column(Modifier.fillMaxSize().padding(horizontal=14.dp)){Row(Modifier.fillMaxWidth().padding(top=10.dp),verticalAlignment=Alignment.CenterVertically){Column(Modifier.weight(1f)){Text("Admin Control Centre",style=MaterialTheme.typography.headlineSmall,fontWeight=FontWeight.Black);Text("Live backend controls",color=MaterialTheme.colorScheme.secondary)};IconButton({busy=true;scope.launch{try{load(token)}catch(e:Throwable){err=e.message?:"Refresh failed"}finally{busy=false}}}){Icon(Icons.Default.Refresh,"Refresh")}}
 Row(Modifier.fillMaxWidth().padding(vertical=8.dp),horizontalArrangement=Arrangement.spacedBy(8.dp)){FilterChip(section=="overview",{section="overview"},{Text("Overview")});FilterChip(section=="users",{section="users"},{Text("Users")});OutlinedButton({scope.launch{runCatching{NexoraApi.adminLogout(token)};s.clearAdmin();token=""}}){Text("Logout")}}
